1	pattern shiftadd
2	//
3	// Transforms add/sub+shift pairs that result from expressions such as data[s*W +C +:W2]
4	// specifically something like: out[W2-1:0] = data >> (s*W +C)
5	// will be transformed into: out[W2-1:0] = (data >> C) >> (s*W)
6	// this can then be optimized using peepopt_shiftmul_right.pmg
7	//
8	
9	match shift
10		select shift->type.in($shift, $shiftx, $shr)
11		filter !port(shift, \B).empty()
12	endmatch
13	
14	// the right shift amount
15	state <SigSpec> shift_amount
16	// log2 scale factor in interpreting of shift_amount
17	// due to zero padding on the shift cell's B port
18	state <int> log2scale
19	// zeros at the MSB position make it unsigned
20	state <bool> msb_zeros
21	
22	code shift_amount log2scale msb_zeros
23		shift_amount = port(shift, \B);
24	
25		log2scale = 0;
26		while (shift_amount[0] == State::S0) {
27			shift_amount.remove(0);
28			if (shift_amount.empty()) reject;
29			log2scale++;
30		}
31	
32		msb_zeros = 0;
33		while (shift_amount.bits().back() == State::S0) {
34			msb_zeros = true;
35			shift_amount.remove(GetSize(shift_amount) - 1);
36			if (shift_amount.empty()) reject;
37		}
38	endcode
39	
40	state <bool>    var_signed
41	state <SigSpec> var_signal
42	// offset: signed constant value c in data[var+c +:W1] (constant shift-right amount)
43	state <int>     offset
44	
45	match add
46		// either data[var+c +:W1] or data[var-c +:W1]
47		select add->type.in($add, $sub)
48		index <SigSpec> port(add, \Y) === shift_amount
49	
50		// one must be constant, the other is variable
51		choice <IdString> constport {\A, \B}
52		select !port(add, constport).empty()
53		select port(add, constport).is_fully_const()
54		define <IdString> varport (constport == \A ? \B : \A)
55	
56		// only optimize for constants up to a fixed width. this prevents cases
57		// with a blowup in internal term size and prevents larger constants being
58		// casted to int incorrectly
59		select (GetSize(port(add, constport)) <= 24)
60	
61		// if a value of var is able to wrap the output, the transformation might give wrong results
62		// an addition/substraction can at most flip one more bit than the largest operand (the carry bit)
63		// as long as the output can show this bit, no wrap should occur (assuming all signed-ness make sense)
64		select ( GetSize(port(add, \Y)) > max(GetSize(port(add, \A)), GetSize(port(add, \B))) )
65	
66		define <bool> varport_A (varport == \A)
67		define <bool> is_sub add->type.in($sub)
68	
69		define <bool> constport_signed param(add, !varport_A ? \A_SIGNED : \B_SIGNED).as_bool()
70		define <bool> varport_signed param(add, varport_A ? \A_SIGNED : \B_SIGNED).as_bool();
71		define <bool> const_negative (constport_signed && (port(add, constport).bits().back() == State::S1))
72		define <bool> offset_negative ((is_sub && varport_A) ^ const_negative)
73	
74		// checking some value boundaries as well:
75		// data[...-c +:W1] is fine for any signed var (pad at LSB, all data still accessible)
76		// unsigned shift may underflow (eg var-3 with var<3) -> cannot be converted
77		// data[...+c +:W1] is only fine for +var(add) and var unsigned
78		// (+c cuts lower C bits, making them inaccessible, a signed var could try to access them)
79		// either its an add or the variable port is A (it must be positive)
80		select (add->type.in($add) || varport == \A)
81	
82		// -> data[var+c +:W1] (with var signed) is illegal
83		filter !(!offset_negative && varport_signed)
84		// -> data >> (var-c) (with var unsigned) is illegal
85		filter !(offset_negative && !varport_signed)
86	
87		// state-variables are assigned at the end only:
88		// shift the log2scale offset in-front of add to get true value: (var+c)<<N -> (var<<N)+(c<<N)
89		set offset ( (port(add, constport).as_int(constport_signed) << log2scale) * ( (is_sub && varport_A) ? -1 : 1 ) )
90	
91		set var_signed varport_signed
92		set var_signal add->getPort(varport)
93	endmatch
94	
95	code
96	{
97		// positive constant offset with a signed variable (index) cannot be handled
98		// the above filter should get rid of this case but 'offset' is calculated differently
99		// due to limitations of state-variables in pmgen
100		// it should only differ if previous passes create invalid data
101		log_assert(!(offset>0 && var_signed));
102	
103		SigSpec old_a = port(shift, \A); // data
104		std::string location = shift->get_src_attribute();
105	
106		if(shiftadd_max_ratio>0 && offset<0 && -offset*shiftadd_max_ratio > old_a.size()) {
107			log_warning("at %s: candiate for shiftadd optimization (shifting '%s' by '%s - %d' bits) "
108						"was ignored to avoid high resource usage, see help peepopt\n",
109						location.c_str(), log_signal(old_a), log_signal(var_signal), -offset);
110			reject;
111		}
112	
113		did_something = true;
114		log("shiftadd pattern in %s: shift=%s, add/sub=%s, offset: %d\n", \
115				module, shift, add, offset);
116	
117		SigSpec new_a;
118		if(offset<0) {
119			// data >> (...-c) transformed to {data, c'X} >> (...)
120			SigSpec padding( (shift->type.in($shiftx) ? State::Sx : State::S0), -offset );
121			new_a.append(padding);
122			new_a.append(old_a);
123		} else {
124			// data >> (...+c) transformed to data[MAX:c] >> (...)
125			if(offset < GetSize(old_a)) { // some signal bits left?
126				new_a.append(old_a.extract_end(offset));
127			} else {
128				// warn user in case data is empty (no bits left)
129				if (location.empty())
130					location = shift->name.str();
131				if(shift->type.in($shiftx))
132					log_warning("at %s: result of indexed part-selection is always constant (selecting from '%s' with index '%s + %d')\n", \
133								location.c_str(), log_signal(old_a), log_signal(var_signal), offset);
134				else
135					log_warning("at %s: result of shift operation is always constant (shifting '%s' by '%s + %d' bits)\n", \
136								location.c_str(), log_signal(old_a), log_signal(var_signal), offset);
137			}
138		}
139	
140		SigSpec new_b = {var_signal, SigSpec(State::S0, log2scale)};
141		if (msb_zeros || !var_signed)
142			new_b.append(State::S0);
143	
144		shift->setPort(\A, new_a);
145		shift->setParam(\A_WIDTH, GetSize(new_a));
146		shift->setPort(\B, new_b);
147		shift->setParam(\B_WIDTH, GetSize(new_b));
148		blacklist(add);
149		accept;
150	}
151	endcode
