generate 100 10
	int width = rng(7) + 1;
	int numsel = rng(4) + 1;
	int idx = rng(numsel);

	SigSpec A = module->addWire(NEW_ID, width);
	SigSpec Y = module->addWire(NEW_ID, width);

	SigSpec B, S;
	for (int i = 0; i < numsel; i++) {
		B.append(module->addWire(NEW_ID, width));
		S.append(i == idx ? port(eq, \Y) : module->addWire(NEW_ID));
